### **개선된 `CutsceneManager.cs` 코드 (핵심 부분)**

```csharp
private int _activeCutsceneCount = 0; // 현재 실행 중인 컷씬 수

public void StartCutscene(GameObject cutsceneActor)
{
    _activeCutsceneCount++;

    // 첫 번째 컷씬이 시작될 때만 게임플레이 플레이어를 비활성화
    if (_activeCutsceneCount == 1)
    {
        if (gameplayPlayer == null) ResolveSceneReferences();
        if (gameplayPlayer != null) gameplayPlayer.SetActive(false);
    }

    // 각 컷씬 전용 배우(Actor) 활성화 및 위치 초기화
    if (cutsceneActor != null)
    {
        if (gameplayPlayer != null)
        {
            cutsceneActor.transform.position = gameplayPlayer.transform.position;
            cutsceneActor.transform.rotation = gameplayPlayer.transform.rotation;
        }
        cutsceneActor.SetActive(true);
    }
}

public void EndCutscene(GameObject cutsceneActor)
{
    // 해당 컷씬 배우 비활성화
    if (cutsceneActor != null)
    {
        // 종료되는 배우의 위치를 플레이어에게 미리 복사 (마지막 배우 기준)
        if (gameplayPlayer != null)
        {
            var cc = gameplayPlayer.GetComponent<CharacterController>();
            if (cc != null) cc.enabled = false;

            gameplayPlayer.transform.position = cutsceneActor.transform.position;
            gameplayPlayer.transform.rotation = cutsceneActor.transform.rotation;

            if (cc != null) cc.enabled = true;
        }
        cutsceneActor.SetActive(false);
    }

    _activeCutsceneCount = Mathf.Max(0, _activeCutsceneCount - 1);

    // 모든 컷씬이 다 끝났을 때만 조작권 반환
    if (_activeCutsceneCount == 0)
    {
        if (gameplayPlayer != null)
        {
            gameplayPlayer.SetActive(true);
            RestoreCameraTarget();
            Debug.Log("[CutsceneManager] 모든 컷씬 종료. 조작권 반환.");
        }
    }
}
```

